  const { data: user, isLoading } = useAuth()
  const navigate = useNavigate()

  useEffect(() => {
    if (!isLoading && user && user.role !== 'ADMIN') {
      navigate('/', { replace: true })
    }
  }, [isLoading, user, navigate])

  if (isLoading || !user || user.role !== 'ADMIN') {
    return null
  }

  return (
    <div>
      <h1>Admin Dashboard</

